import React, { useState } from "react";
import axios from "axios";
import "./App.css";
import IndividualAnalysis from "./IndividualAnalysis";
import BatchAnalysis from "./BatchAnalysis";

const API_BASE = "http://localhost:5000/api";

function App() {
  const [mode, setMode] = useState("individual");
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState(null);
  const [batchResults, setBatchResults] = useState(null);
  const [batchFile, setBatchFile] = useState(null);

  const [customerData, setCustomerData] = useState({
    Tenure: 5.0,
    OrderCount: 5.0,
    CashbackAmount: 12000.0,
    DaySinceLastOrder: 7.0,
    HourSpendOnApp: 30.0,
    OrderAmountHikeFromlastYear: 15.0,
    CouponUsed: 1,
    NumberOfDeviceRegistered: 3,
    Complain: 0,
    SatisfactionScore: 3,
    WarehouseToHome: 10.0,
    NumberOfAddress: 4,
    CityTier: 1,
    PreferredLoginDevice: "Mobile Phone",
    PreferredPaymentMode: "Credit Card",
    PreferedOrderCat: "Laptop & Accessory",
    Gender: "Male",
    MaritalStatus: "Married",
  });

  const handleIndividualAnalyze = async () => {
    setLoading(true);
    try {
      const res = await axios.post(`${API_BASE}/individual`, customerData);
      setResults(res.data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleBatchAnalyze = async () => {
    if (!batchFile) return;
    setLoading(true);
    const formData = new FormData();
    formData.append("file", batchFile);
    try {
      const res = await axios.post(`${API_BASE}/batch`, formData);
      setBatchResults(res.data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="app">
      {/* Top Navigation */}
      <nav className="top-nav">
        <div className="brand">
          <span className="logo-text">AI<span>Churn</span></span>
        </div>
        <div className="mode-switch">
          <button
            className={`mode-btn ${mode === "individual" ? "active" : ""}`}
            onClick={() => setMode("individual")}
          >
            Individual Mode
          </button>
          <button
            className={`mode-btn ${mode === "batch" ? "active" : ""}`}
            onClick={() => setMode("batch")}
          >
            Batch Mode
          </button>
        </div>
        <div className="nav-actions">
          <button className="nav-action-btn">Docs</button>
          <button className="nav-action-btn outline">Support</button>
        </div>
      </nav>

      {/* Hero Section */}
      <section className="hero-section">
        <div className="hero-content">
          <h1>Executive Customer Churn Dashboard</h1>
          <p>
            Empower your business with real-time predictive insights and customer retention analytics.
          </p>
        </div>

        <div className="kpi-container">
          <div className="kpi-card">
            <h3>Active Users</h3>
            <p>12,940</p>
          </div>
          <div className="kpi-card">
            <h3>Churn Risk</h3>
            <p>18%</p>
          </div>
          <div className="kpi-card">
            <h3>Predictions Run</h3>
            <p>2,348</p>
          </div>
        </div>
      </section>

      {/* Analysis Section */}
      <main className="main-content">
        <div className="panel">
          {mode === "individual" ? (
            <IndividualAnalysis
              customerData={customerData}
              onInputChange={setCustomerData}
              onAnalyze={handleIndividualAnalyze}
              loading={loading}
              results={results}
            />
          ) : (
            <BatchAnalysis
              onFileChange={(e) => setBatchFile(e.target.files[0])}
              onAnalyze={handleBatchAnalyze}
              loading={loading}
              results={batchResults}
            />
          )}
        </div>
      </main>

      <footer className="footer">
        <p>© 2025 AI Churn Intelligence — Designed for Enterprise Analytics</p>
      </footer>
    </div>
  );
}

export default App;
